func testAccComputeBulkPerInstanceConfig_basic(context map[string]any) string {
	return testAccComputeBulkPerInstanceConfig_igm(context) + acctest.Nprintf(`
resource "google_compute_bulk_per_instance_config" "default" {
	instance_group_manager = google_compute_instance_group_manager.igm.name
	instances {
		name = "%{instance_name1}"
	}
	instances {
		name = "%{instance_name2}"
	}
}

`, context)
}

func testAccComputeBulkPerInstanceConfig_igm(context map[string]any) string {
	return acctest.Nprintf(`
data "google_compute_image" "my_image" {
  family  = "debian-11"
  project = "debian-cloud"
}

resource "google_compute_instance_template" "igm-basic" {
  name           = "tf-test-igm-%{random_suffix}"
  machine_type   = "e2-medium"

  disk {
    source_image = data.google_compute_image.my_image.self_link
    auto_delete  = true
    boot         = true
  }

  network_interface {
    network = "default"
  }
}

resource "google_compute_instance_group_manager" "igm" {
  description = "Terraform test instance group manager"
  name        = "%{igm_name}"

  version {
    name              = "prod"
    instance_template = google_compute_instance_template.igm-basic.self_link
  }

  base_instance_name = "tf-test-igm-no-tp"

  lifecycle {
    # Bulk per-instance configs manage the number of instances, so ignore target_size changes.
    ignore_changes = [target_size]
  }
}

`, context)
}

// Checks that bulk per instance config with the given name was destroyed
func testAccCheckComputeBulkPerInstanceConfigInstancesCreated(t *testing.T, igmId string, instanceNames []string) resource.TestCheckFunc {
	return func(s *terraform.State) error {
		foundInstanceNames, err := testAccComputeBulkPerInstanceConfigListInstanceNames(t, igmId)
		if err != nil {
			return fmt.Errorf("unable to confirm config was destroyed: %v", err)
		}

		var createdInstanceNames []string
		for _, instanceName := range instanceNames {
			if slices.Contains(foundInstanceNames, instanceName) {
				createdInstanceNames = append(createdInstanceNames, instanceName)
			}
		}
		if len(createdInstanceNames) != len(instanceNames) {
			return fmt.Errorf("Not all instances for bulk per instance config were created: %#v", createdInstanceNames)
		}

		return nil
	}
}

// Checks that bulk per instance config with the given name was destroyed
func testAccCheckComputeBulkPerInstanceConfigInstancesDeleted(t *testing.T, igmId string, instanceNames []string) resource.TestCheckFunc {
	return func(s *terraform.State) error {
		foundInstanceNames, err := testAccComputeBulkPerInstanceConfigListInstanceNames(t, igmId)
		if err != nil {
			return fmt.Errorf("unable to confirm config was destroyed: %v", err)
		}
		var notDeletedInstanceNames []string
		for _, instanceName := range instanceNames {
			if slices.Contains(foundInstanceNames, instanceName) {
				notDeletedInstanceNames = append(notDeletedInstanceNames, instanceName)
			}
		}
		if len(notDeletedInstanceNames) != 0 {
			return fmt.Errorf("Not all instances for bulk per instance config were removed: %#v", notDeletedInstanceNames)
		}

		return nil
	}
}

func testAccComputeBulkPerInstanceConfigListInstanceNames(t *testing.T, igmId string) ([]string, error) {
	config := acctest.GoogleProviderConfig(t)

	url := fmt.Sprintf("%s%s/listManagedInstances", transport_tpg.BaseUrl(compute.Product, config), igmId)
	res, err := transport_tpg.SendRequest(transport_tpg.SendRequestOptions{
		Config:    config,
		Method:    "POST",
		RawURL:    url,
		UserAgent: config.UserAgent,
	})
	if err != nil {
		return nil, err
	}

	v, ok := res["managedInstances"]
	if !ok || v == nil {
		return nil, nil
	}
	managedInstancesRaw := v.([]any)
	var instanceNames []string
	for _, managedInstanceRaw := range managedInstancesRaw {
		managedInstance := managedInstanceRaw.(map[string]any)
		instanceNames = append(instanceNames, managedInstance["name"].(string))
	}
	return instanceNames, nil
}
